import React, { useEffect, useState } from 'react'
import { Avatar, Box, Button, Card, CardActions, CardContent, CardHeader, Divider, Grid, IconButton, List, ListItem, ListItemIcon, ListItemText, makeStyles, Paper, TextField, Typography } from '@material-ui/core'
import Cookies from 'js-cookie'

import axios from 'axios'
import { Link } from 'react-router-dom'
import { DescriptionRounded, FiberManualRecordRounded, SendRounded } from '@material-ui/icons'

const useStyle = makeStyles((theme) => {
    return {
        root: {
            '& .MuiCard-root': {
                transform: 'none',
                [theme.breakpoints.down('xs')]: {
                    margin: '0'
                },
                '&:hover': {
                    transform: 'none',
                    boxShadow: 'none'
                }
            },
            '& .MuiPaper-root': {
                transform: 'none',
                [theme.breakpoints.down('xs')]: {
                    margin: '0'
                },
                '&:hover': {
                    transform: 'none',
                    boxShadow: 'none'
                }
            }
        },
        cardLink: {
            textDecoration: 'none',
            color: 'inherit',
            fontSize: 0
        },
        list: {
            border: '1px solid rgba(0,0,0,0.2)',
            borderRadius: '5px',
            marginTop: theme.spacing(2),
            '&:hover': {
                transform: 'scale(1.007)',
                backgroundColor: 'rgba(0,0,0,0.1)',
                cursor: 'pointer'
            }
        },
        listText: {
            overflow: 'hidden',
            textOverflow: 'ellipsis',
            whiteSpace: 'nowrap',
            maxWidth: theme.spacing(50)
        },
        smallAvatar: {
            width: theme.spacing(3.7),
            height: theme.spacing(3.7)
        }
    }
})

export default function StudentPosts({ activity, img }) {
    const classes = useStyle()

    const file = JSON.parse(activity.files)


    const filesCollection = []

    for (const key in file) {
        filesCollection.push( file[key] )
    }

    return (
        <Box className={classes.root}>
            <Card variant='outlined'>
                <CardHeader avatar={
                    <Avatar src={img} />
                }
                    title={activity.nameWhoPosted}
                    subheader={'Sept. 3'}
                />
                <CardContent>


                    <Typography variant='h6'>
                        {activity.title}
                    </Typography>
                    <Typography variant='body2' >
                        {activity.body}
                    </Typography>

                    {/* <List disablePadding dense>{filesCollection}</List> */}
                    <List>
                        {
                            filesCollection.map(keys => (
                                <ListItem className={classes.list} key={keys}>
                                    <ListItemIcon><DescriptionRounded /></ListItemIcon>
                                    <ListItemText className={classes.listText}>{keys}</ListItemText>
                                </ListItem>
                            ))
                        }
                    </List>

                </CardContent>

                <Divider />

                <Box ml={2} mb={2} mt={2} mr={2}>
                    <Grid container direction='row' alignItems='center' >
                        <Grid item xs={1}>
                            <Avatar className={classes.smallAvatar} />
                        </Grid>
                        <Grid item xs={10} >
                            <TextField variant='outlined' placeholder='Make a comment...' size='small' fullWidth />
                        </Grid>
                        <Grid item xs={1} >
                            <IconButton>
                                <SendRounded size='small' />
                            </IconButton>
                        </Grid>
                    </Grid>
                </Box>

            </Card>
        </Box>
    )
}
